import{mostrarResultado}from"../../renderResult.js";export function render(t){const{productos:n,carrito:o,total:r}=t.respuesta,d=n.map(t=>`\n        <div style="border:1px solid #ccc; padding:10px; margin:5px; display:inline-block; width:150px;">\n            <img src="${t.imagen}" alt="${t.nombre}" style="width:100%;"><br>\n            <b>${t.nombre}</b><br>\n            ${t.precio} € <br>\n            <button onclick="sendPrompt('accion=añadir&productoId=${t.id}')">🛒 Comprar</button>\n        </div>\n    `).join(""),a=0===o.length?"<p>El carrito está vacío.</p>":`<table border="1">\n            <thead><tr><th>Producto</th><th>Precio</th><th>Uds.</th><th>Subtotal</th><th></th></tr></thead>\n            <tbody>\n                ${o.map(t=>`\n                    <tr>\n                        <td>${t.nombre}</td>\n                        <td>${t.precio} €</td>\n                        <td>${t.cantidad}</td>\n                        <td>${t.subtotal} €</td>\n                        <td><button onclick="sendPrompt('accion=eliminar&productoId=${t.id}')">🗑 Eliminar</button></td>\n                    </tr>\n                `).join("")}\n            </tbody>\n            <tfoot><tr><td colspan="3"><b>Total</b></td><td colspan="2"><b>${r} €</b></td></tr></tfoot>\n        </table>`;mostrarResultado(`\n        <h3>Catálogo</h3>\n        ${d}\n        <hr>\n        <h3>Carrito</h3>\n        ${a}\n    `)}//# sourceMappingURL=ejercicio5.js.map
